import * as React from "react";

const MOBILE_BREAKPOINT = 768;

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined);

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`);
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT);
    };
    mql.addEventListener("change", onChange);
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT);
    return () => mql.removeEventListener("change", onChange);
  }, []);

  return !!isMobile;
}

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export interface AccountHealth {
    activeCampaigns: number;
    maxCampaigns: number;
    activeIntegrations: number;
    maxIntegrations: number;
    lastSyncAt: string | null;
    integrationStatus: 'connected' | 'expired' | 'error' | 'not_connected';
    alerts: Array<{
        type: 'warning' | 'error' | 'info';
        message: string;
    }>;
}

export function useAccountHealth() {
    const { user } = useAuth();
    const companyId = user?.company?.id;

    return useQuery({
        queryKey: ['account-health', companyId],
        queryFn: async (): Promise<AccountHealth> => {
            if (!companyId) throw new Error('No company ID');

            // Get company limits
            const { data: company, error: companyError } = await supabase
                .from('companies')
                .select('max_campaigns, max_integrations')
                .eq('id', companyId)
                .single();

            if (companyError) throw companyError;

            // Get active campaigns count
            const { count: activeCampaigns } = await supabase
                .from('campaigns')
                .select('*', { count: 'exact', head: true })
                .eq('company_id', companyId)
                .eq('status', 'active');

            // Get integrations
            const { data: integrations } = await supabase
                .from('integrations')
                .select('status, last_sync_at, token_expires_at')
                .eq('company_id', companyId)
                .eq('platform', 'meta');

            const activeIntegrations = integrations?.filter(i => i.status === 'active').length || 0;
            const latestSync = integrations?.map(i => i.last_sync_at).filter(Boolean).sort().reverse()[0] || null;

            // Determine integration status
            let integrationStatus: AccountHealth['integrationStatus'] = 'not_connected';
            if (integrations && integrations.length > 0) {
                const hasExpired = integrations.some(i =>
                    i.token_expires_at && new Date(i.token_expires_at) < new Date()
                );
                const hasError = integrations.some(i => i.status === 'error');

                if (hasExpired) {
                    integrationStatus = 'expired';
                } else if (hasError) {
                    integrationStatus = 'error';
                } else if (activeIntegrations > 0) {
                    integrationStatus = 'connected';
                }
            }

            // Generate alerts
            const alerts: AccountHealth['alerts'] = [];

            if (integrationStatus === 'expired') {
                alerts.push({ type: 'warning', message: 'Token do Meta expirado. Reconecte sua conta.' });
            }

            if (integrationStatus === 'not_connected') {
                alerts.push({ type: 'info', message: 'Conecte sua conta do Meta para começar.' });
            }

            if (activeCampaigns && company?.max_campaigns && activeCampaigns >= company.max_campaigns * 0.9) {
                alerts.push({ type: 'warning', message: `Você está próximo do limite de campanhas (${activeCampaigns}/${company.max_campaigns}).` });
            }

            return {
                activeCampaigns: activeCampaigns || 0,
                maxCampaigns: company?.max_campaigns || 10,
                activeIntegrations,
                maxIntegrations: company?.max_integrations || 2,
                lastSyncAt: latestSync,
                integrationStatus,
                alerts,
            };
        },
        enabled: !!companyId,
        staleTime: 2 * 60 * 1000,
    });
}

export function useSyncStatus() {
    const { user } = useAuth();
    const companyId = user?.company?.id;

    return useQuery({
        queryKey: ['sync-status', companyId],
        queryFn: async () => {
            if (!companyId) throw new Error('No company ID');

            const { data, error } = await supabase
                .from('sync_history')
                .select('*')
                .eq('company_id', companyId)
                .order('created_at', { ascending: false })
                .limit(5);

            if (error) throw error;
            return data || [];
        },
        enabled: !!companyId,
        staleTime: 1 * 60 * 1000,
    });
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase, supabaseUrl } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';

export interface Audit {
    id: string;
    company_id: string;
    creative_id: string;
    policy_id: string | null;
    status: string | null;
    compliance_score: number | null;
    performance_score: number | null;
    issues: AuditIssue[] | null;
    recommendations: string[] | null;
    ai_analysis: AiAnalysis | null;
    created_at: string;
    // Joined data
    creatives?: {
        name: string;
        image_url: string | null;
        type: string | null;
    };
    policies?: {
        name: string;
    };
}

export interface AuditIssue {
    type: 'keyword' | 'text_length' | 'brand' | 'performance';
    severity: 'error' | 'warning' | 'info';
    message: string;
    details?: Record<string, unknown>;
}

export interface AiAnalysis {
    quality_score?: number;
    tone_analysis?: string;
    strengths?: string[];
    weaknesses?: string[];
    suggestions?: string[];
}

export function useAudits() {
    const { user } = useAuth();
    const queryClient = useQueryClient();
    const companyId = user?.company?.id;

    const auditsQuery = useQuery({
        queryKey: ['audits', companyId],
        queryFn: async () => {
            if (!companyId) throw new Error('No company ID');

            const { data, error } = await supabase
                .from('audits')
                .select(`
          *,
          creatives(name, image_url, type),
          policies(name)
        `)
                .eq('company_id', companyId)
                .order('created_at', { ascending: false })
                .limit(100);

            if (error) throw error;
            return data as unknown as Audit[];
        },
        enabled: !!companyId,
    });

    const runAudit = useMutation({
        mutationFn: async ({ creativeId, policyId }: { creativeId: string; policyId?: string }) => {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('No session');

            const response = await fetch(
                `${supabaseUrl}/functions/v1/audit-creative`,
                {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${session.access_token}`,
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        creative_id: creativeId,
                        policy_id: policyId,
                    }),
                }
            );

            if (!response.ok) {
                const error = await response.json();
                throw new Error(error.error || 'Audit failed');
            }

            return response.json();
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['audits', companyId] });
            toast.success('Auditoria concluída');
        },
        onError: (error) => {
            toast.error(`Erro na auditoria: ${error.message}`);
        },
    });

    const runBatchAudit = useMutation({
        mutationFn: async ({ campaignId, policyId, limit }: { campaignId?: string; policyId?: string; limit?: number }) => {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('No session');

            const response = await fetch(
                `${supabaseUrl}/functions/v1/audit-batch`,
                {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${session.access_token}`,
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        campaign_id: campaignId,
                        policy_id: policyId,
                        limit,
                    }),
                }
            );

            if (!response.ok) {
                const error = await response.json();
                throw new Error(error.error || 'Batch audit failed');
            }

            return response.json();
        },
        onSuccess: (data) => {
            queryClient.invalidateQueries({ queryKey: ['audits', companyId] });
            toast.success(`Auditoria em lote concluída: ${data.audited} criativos`);
        },
        onError: (error) => {
            toast.error(`Erro na auditoria em lote: ${error.message}`);
        },
    });

    return {
        audits: auditsQuery.data || [],
        isLoading: auditsQuery.isLoading,
        error: auditsQuery.error,
        runAudit,
        runBatchAudit,
    };
}

export function useAuditsCount() {
    const { user } = useAuth();
    const companyId = user?.company?.id;

    return useQuery({
        queryKey: ['audits-count', companyId],
        queryFn: async () => {
            if (!companyId) throw new Error('No company ID');

            const { count: total, error: totalError } = await supabase
                .from('audits')
                .select('*', { count: 'exact', head: true })
                .eq('company_id', companyId);

            if (totalError) throw totalError;

            const { count: pending, error: pendingError } = await supabase
                .from('audits')
                .select('*', { count: 'exact', head: true })
                .eq('company_id', companyId)
                .eq('status', 'pending');

            if (pendingError) throw pendingError;

            return {
                total: total || 0,
                pending: pending || 0
            };
        },
        enabled: !!companyId,
        staleTime: 5 * 60 * 1000,
    });
}

