                .select(`
                    *,
                    creative:creatives(name, image_url)
                `)
                .eq('company_id', companyId)
                .eq('status', 'rejected')
                .order('created_at', { ascending: false })
                .limit(limit);

            if (error) throw error;
            return data || [];
        },
        enabled: !!companyId,
        staleTime: 5 * 60 * 1000,
    });
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { useToast } from '@/hooks/use-toast';

// Usando tipos compatíveis com schema Supabase
export interface Company {
    id: string;
    name: string;
    slug: string;
    logo_url: string | null;
    max_campaigns: number;
    max_integrations: number;
    max_users: number;
    created_at: string;
}

export interface UpdateCompanyInput {
    name?: string;
    logo_url?: string | null;
}

export function useCompany() {
    const { user } = useAuth();
    const companyId = user?.company?.id;

    return useQuery({
        queryKey: ['company', companyId],
        queryFn: async (): Promise<Company> => {
            if (!companyId) throw new Error('No company ID');

            const { data, error } = await supabase
                .from('companies')
                .select('id, name, slug, logo_url, max_campaigns, max_integrations, max_users, created_at')
                .eq('id', companyId)
                .single();

            if (error) throw error;
            return data as Company;
        },
        enabled: !!companyId,
        staleTime: 5 * 60 * 1000,
    });
}

export function useUpdateCompany() {
    const { user } = useAuth();
    const companyId = user?.company?.id;
    const queryClient = useQueryClient();
    const { toast } = useToast();

    return useMutation({
        mutationFn: async (updates: UpdateCompanyInput) => {
            if (!companyId) throw new Error('No company ID');

            const { data, error } = await supabase
                .from('companies')
                .update(updates)
                .eq('id', companyId)
                .select()
                .single();

            if (error) throw error;
            return data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['company'] });
            toast({
                title: 'Empresa atualizada',
                description: 'As configurações foram salvas.',
            });
        },
        onError: (error) => {
            toast({
                title: 'Erro ao atualizar',
                description: String(error),
                variant: 'destructive',
            });
        },
    });
}

export function useCompanyStats() {
    const { user } = useAuth();
    const companyId = user?.company?.id;

    return useQuery({
        queryKey: ['company-stats', companyId],
        queryFn: async () => {
            if (!companyId) throw new Error('No company ID');

            const [campaigns, integrations, users, audits] = await Promise.all([
                supabase.from('campaigns').select('*', { count: 'exact', head: true }).eq('company_id', companyId),
                supabase.from('integrations').select('*', { count: 'exact', head: true }).eq('company_id', companyId).eq('status', 'active'),
                supabase.from('users').select('*', { count: 'exact', head: true }).eq('company_id', companyId),
                supabase.from('audits').select('*', { count: 'exact', head: true }).eq('company_id', companyId),
            ]);

            return {
                totalCampaigns: campaigns.count || 0,
                activeIntegrations: integrations.count || 0,
                totalUsers: users.count || 0,
                totalAudits: audits.count || 0,
            };
        },
        enabled: !!companyId,
        staleTime: 5 * 60 * 1000,
    });
}
